62:         }
63: 
64:         match (a.kind(), b.kind()) {
65:             (
66:                 _,
67:                 &ty::Infer(ty::FreshTy(_))
68:                 | &ty::Infer(ty::FreshIntTy(_))
69:                 | &ty::Infer(ty::FreshFloatTy(_)),
